import React from "react";
import "./navbar.css";

function Navbar() {
  return (
    <section className="navBarSection">
      <header className="header flex">
        <div className="logoDiv">
          <a href="#" className="logo flex">
            <img src="\images\result.png" alt="Biscoza"></img>
          </a>
        </div>
      </header>
    </section>
  );
}

export default Navbar;
